/**
 * Display welcome tips
 */
export function displayWelcomeTips() {
    console.log(chalk.gray('\nTips for getting started:'));
    console.log(chalk.gray('1. Ask questions, edit files, or run commands.'));
    console.log(chalk.gray('2. Be specific for the best results.'));
    console.log(chalk.gray('3. Create ') + chalk.white('CODESTRAL.md') + chalk.gray(' files to customize your interactions with Codestral.'));
    console.log(chalk.gray('4. ') + chalk.white('/help') + chalk.gray(' for more information.'));
    console.log();
}

/**
 * Display status bar at bottom
 */
export function displayStatusBar(options = {}) {
    const {
        workingDir = process.cwd().split('/').pop(),
        mode = 'safe',
        model = 'mistral-large-latest',
        contextUsage = 0
    } = options;

    const modeText = mode === 'safe' ? 'safe mode' : mode === 'autonomous' ? 'autonomous mode' : 'full autonomy';
    const contextText = `(${contextUsage}% context used)`;

    const leftPart = chalk.gray(`~/${workingDir}`);
    const middlePart = chalk.gray(`${modeText} (see /docs)`);
    const rightPart = chalk.gray(`${model} ${contextText}`);

    // Calculate spacing to distribute evenly
    const terminalWidth = process.stdout.columns || 100;
    const leftText = `~/${workingDir}`;
    const middleText = `${modeText} (see /docs)`;
    const rightText = `${model} ${contextText}`;

    const totalTextLen = leftText.length + middleText.length + rightText.length;
    const availableSpace = terminalWidth - totalTextLen;
    const spacing1 = Math.max(2, Math.floor(availableSpace / 2));
    const spacing2 = Math.max(2, availableSpace - spacing1);

    console.log(leftPart + ' '.repeat(spacing1) + middlePart + ' '.repeat(spacing2) + rightPart);
}

/**
 * Display input box border (top)
 */
export function displayInputBoxTop() {
    const terminalWidth = process.stdout.columns || 100;
    const border = '‚ĒÄ'.repeat(terminalWidth - 2);
    console.log(chalk.gray(`‚ē≠${border}‚ēģ`));
}

/**
 * Display input box border (bottom)
 */
export function displayInputBoxBottom() {
    const terminalWidth = process.stdout.columns || 100;
    const border = '‚ĒÄ'.repeat(terminalWidth - 2);
    console.log(chalk.gray(`‚ēį${border}‚ēĮ`));
}

/**
 * Get custom prompt with green cursor
 */
export function getPrompt() {
    return chalk.gray('‚Ēā ') + chalk.green('‚Ėą ') + chalk.gray('Type your message or @path/to/file');
}

export default {
    displayLogo,
    displayWelcomeTips,
    displayStatusBar,
    displayInputBoxTop,
    displayInputBoxBottom,
    getPrompt
};
